DROP TABLE IF EXISTS `products`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `products` (
  `id` int NOT NULL AUTO_INCREMENT,
  `sku` varchar(100) DEFAULT NULL,
  `name` varchar(150) NOT NULL,
  `category` enum('school_supply','id_supplies','id_services','printing','photocopy','other') NOT NULL DEFAULT 'school_supply',
  `product_group` enum('product','igp','service') NOT NULL DEFAULT 'product',
  `type` enum('item','service') NOT NULL DEFAULT 'item',
  `cost_price` decimal(12,2) NOT NULL DEFAULT '0.00',
  `selling_price` decimal(12,2) NOT NULL DEFAULT '0.00',
  `stock_qty` int NOT NULL DEFAULT '0',
  `low_stock_threshold` int NOT NULL DEFAULT '5',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `sku` (`sku`),
  KEY `idx_products_active_name` (`is_active`,`name`),
  KEY `idx_products_active_category` (`is_active`,`category`),
  KEY `idx_products_active_group` (`is_active`,`product_group`),
  KEY `idx_products_active_sku` (`is_active`,`sku`)
) ENGINE=InnoDB AUTO_INCREMENT=7081 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
