CREATE OR REPLACE VIEW `v_inventory_category_summary` AS
SELECT COALESCE(NULLIF(`category_name`, ''), `category`) AS `category`, COUNT(*) AS `product_count`, COALESCE(SUM(CASE WHEN `type` = 'item' THEN `stock_qty` ELSE 0 END), 0) AS `stock_units`, COALESCE(SUM(CASE WHEN `type` = 'item' THEN `stock_qty` * `selling_price` ELSE 0 END), 0) AS `stock_value`, COALESCE(SUM(CASE WHEN `type` = 'item' AND `stock_qty` <= `low_stock_threshold` THEN 1 ELSE 0 END), 0) AS `low_stock_count`
FROM `products`
WHERE `is_active` = 1
GROUP BY COALESCE(NULLIF(`category_name`, ''), `category`);

